import React, {
  useState,
  useEffect,
  useRef,
  useContext,
  createContext
} from "react";

// Create Context
const UserContext = createContext();

function App() {

  // useState
  const [count, setCount] = useState(0);

  // useRef
  const inputRef = useRef();

  // useEffect
  useEffect(() => {
    console.log("Page Loaded or Count Changed");
  }, [count]);

  const userName = "Vicky";

  return (
    <UserContext.Provider value={userName}>

      <div style={{ textAlign: "center", marginTop: "50px" }}>

        <h1>React 4 Hooks Example</h1>

        {/* useState */}
        <h2>Count: {count}</h2>

        <button onClick={() => setCount(count + 1)}>
          Increase
        </button>

        <hr />

        {/* useRef */}
        <input
          type="text"
          ref={inputRef}
          placeholder="Type here"
        />

        <button onClick={() => inputRef.current.focus()}>
          Focus Input
        </button>

        <hr />

        {/* useContext */}
        <ChildComponent />

      </div>

    </UserContext.Provider>
  );
}

// Child Component
function ChildComponent() {

  const user = useContext(UserContext);

  return (
    <div>
      <h2>Hello {user}</h2>
    </div>
  );
}

export default App;
